// Normaliza payload — GHL puede mandar como query, body, o body string
const raw = $input.first().json;
let src = {};
if (raw && typeof raw.body === 'object' && Object.keys(raw.body).length) src = raw.body;
else if (raw && typeof raw.query === 'object' && Object.keys(raw.query).length) src = raw.query;
else if (typeof raw === 'object') src = raw;

// Parser de fecha GHL: "Thursday, April 30, 2026 3:30 PM" → ISO con offset Cancún (-05:00)
const MONTHS = {January:0,February:1,March:2,April:3,May:4,June:5,July:6,August:7,September:8,October:9,November:10,December:11};
function parseGHLDate(s) {
  if (!s || typeof s !== 'string') return null;
  const m = s.match(/\w+,\s+(\w+)\s+(\d+),\s+(\d+)\s+(\d+):(\d+)\s*(AM|PM)/i);
  if (!m) return null;
  let [, mon, day, year, h, mi, ap] = m;
  let H = parseInt(h, 10) % 12;
  if (/PM/i.test(ap)) H += 12;
  const mon_n = MONTHS[mon];
  if (mon_n === undefined) return null;
  const pad = (n) => String(n).padStart(2, '0');
  // Cancún = UTC-5 fijo (sin DST desde 2015)
  return `${year}-${pad(mon_n + 1)}-${pad(day)}T${pad(H)}:${pad(mi)}:00-05:00`;
}

// Normaliza phone: "998 346 3802" → "529983463802"
function normalizePhone(p) {
  if (!p) return null;
  const digits = String(p).replace(/\D/g, '');
  if (!digits) return null;
  if (digits.startsWith('52')) return digits;
  if (digits.length === 10) return '52' + digits;
  return digits;
}

const startISO = parseGHLDate(src.start_time);
const endISO = parseGHLDate(src.end_time);
const startDate = startISO ? startISO.slice(0, 10) : null;
const startTimeOnly = startISO ? startISO.slice(11, 19) : null;
const durationMin = (startISO && endISO) ? Math.round((new Date(endISO) - new Date(startISO)) / 60000) : null;

// booking_code corto y único
function shortCode() {
  const ts = Date.now().toString(36).toUpperCase().slice(-5);
  const rnd = Math.random().toString(36).toUpperCase().slice(2, 5);
  return `EX-${ts}${rnd}`;
}

const nombre = [src.first_name, src.last_name].filter(Boolean).join(' ').trim() || null;

return [{
  json: {
    ghl_appointment_id: src.appointment_id || null,
    ghl_contact_id: src.contact_id || null,
    cliente_email: src.email || null,
    cliente_telefono: normalizePhone(src.phone),
    cliente_nombre: nombre,
    fecha_agendada: startDate,
    hora_agendada: startTimeOnly,
    duracion_total_min: durationMin,
    start_iso: startISO,
    end_iso: endISO,
    booking_code: shortCode(),
    raw_start_time: src.start_time,
    raw_end_time: src.end_time
  }
}];
